def calculator(expr):
    expr = expr.replace(' ', '')
    tokens = []
    num = ''
    for c in expr:
        if c.isdigit():
            num += c
        else:
            if num:
                tokens.append(int(num))
                num = ''
            tokens.append(c)
    if num:
        tokens.append(int(num))
    i = 0
    while i < len(tokens):
        if tokens[i] == '*':
            tokens[i-1:i+2] = [tokens[i-1] * tokens[i+1]]
        else:
            i += 1
    result = tokens[0]
    i = 1
    while i < len(tokens):
        if tokens[i] == '+':
            result += tokens[i+1]
        elif tokens[i] == '-':
            result -= tokens[i+1]
        i += 2
    return result
